import 'package:flutter/material.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

// Cores centralizadas para todo o componente
class GridColors {
  static const Color primary = Color(0xFF93070A);
  static const Color primaryDark = Color(0xFF6A0507);
  static const Color primaryLight = Color(0xFFB84042);
  static const Color secondary = Color(0xFF005826);
  static const Color secondaryLight = Color(0xFF2E7D32);
  static const Color secondaryDark = Color(0xFF003D1A);
  static const Color textPrimary = Color(0xFFFFFFFF);
  static const Color textSecondary = Color(0xFF000000);
  static const Color link = Color(0xFFFF0000);
  static const Color inputBackground = Color(0xFFFFFFFF);
  static const Color inputBorder = Color(0xFF93070A);
  static const Color buttonBackground = Color(0xFF93070A);
  static const Color buttonText = Color(0xFFFFFFFF);
  static const Color background = Color(0xFF005826);
  static const Color card = Color(0xFFFFFFFF);
  static const Color error = Color(0xFFD32F2F);
  static const Color warning = Color(0xFFFFA000);
  static const Color success = Color(0xFF2E7D32);
  static const Color info = Color(0xFF1976D2);
  static const Color divider = Color(0xFFBDBDBD);
  static const Color filterBackground = Color(0xFFEFEFEF);
  static const Color hover = Color(0x1A000000);
  static const Color selectedRow = Color(0xFFE3F2FD);
  static const Color dialogBackground = Color(0xFFFFFFFF);
  static const Color shadow = Color(0x26000000);
}

class Role {
  final int id;
  final String description;

  Role({required this.id, required this.description});

  factory Role.fromJson(Map<String, dynamic> json) {
    return Role(
      id: json['id'],
      description: json['description'],
    );
  }
}

class RoleService {
  static Future<List<Role>> getRoles() async {
    final response = await http.get(Uri.parse('http://localhost:8080/api/role?size=1000'));

    if (response.statusCode == 200) {
      // Assumindo que a resposta tem uma estrutura de paginação
      final data = jsonDecode(response.body);
      final List<dynamic> rolesJson = data['data']['content']; // Ajuste conforme a estrutura da resposta
      return rolesJson.map((json) => Role.fromJson(json)).toList();
    } else {
      throw Exception('Falha ao carregar roles');
    }
  }

  static Future<void> associateRoleToLogin(int loginId, int roleId) async {
    final response = await http.post(
      Uri.parse('http://localhost:8080/api/login/$loginId/roles/$roleId'),
    );

    if (response.statusCode != 200) {
      throw Exception('Falha ao associar role');
    }
  }
}

class BaixaDialog extends StatefulWidget {
  final int loginId;

  const BaixaDialog({Key? key, required this.loginId}) : super(key: key);

  @override
  _BaixaDialogState createState() => _BaixaDialogState();
}

class _BaixaDialogState extends State<BaixaDialog> {
  Role? _selectedRole;
  List<Role> _roles = [];
  bool _isLoading = true;
  String? _error;

  @override
  void initState() {
    super.initState();
    _loadRoles();
  }

  _loadRoles() async {
    try {
      final roles = await RoleService.getRoles();
      setState(() {
        _roles = roles;
        _isLoading = false;
      });
    } catch (e) {
      setState(() {
        _error = e.toString();
        _isLoading = false;
      });
    }
  }

  _associateRole() async {
    if (_selectedRole == null) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Selecione uma role'),
          backgroundColor: GridColors.error,
        ),
      );
      return;
    }

    try {
      await RoleService.associateRoleToLogin(widget.loginId, _selectedRole!.id);
      Navigator.of(context).pop(true); // Fecha o diálogo e indica sucesso
    } catch (e) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(
          content: Text('Erro ao associar role: $e'),
          backgroundColor: GridColors.error,
        ),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Dialog(
      backgroundColor: GridColors.dialogBackground,
      shape: RoundedRectangleBorder(
        borderRadius: BorderRadius.circular(8.0),
      ),
      child: Padding(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Text(
              'Associar Role',
              style: TextStyle(
                fontSize: 18,
                fontWeight: FontWeight.bold,
                color: GridColors.textSecondary,
              ),
            ),
            SizedBox(height: 16),
            if (_isLoading)
              Center(child: CircularProgressIndicator())
            else if (_error != null)
              Text(
                _error!,
                style: TextStyle(color: GridColors.error),
              )
            else
              DropdownButtonFormField<Role>(
                decoration: InputDecoration(
                  labelText: 'Role',
                  labelStyle: TextStyle(color: GridColors.inputBorder),
                  enabledBorder: OutlineInputBorder(
                    borderSide: BorderSide(color: GridColors.inputBorder),
                  ),
                  focusedBorder: OutlineInputBorder(
                    borderSide: BorderSide(color: GridColors.primary),
                  ),
                ),
                value: _selectedRole,
                items: _roles.map((Role role) {
                  return DropdownMenuItem<Role>(
                    value: role,
                    child: Text(role.description),
                  );
                }).toList(),
                onChanged: (Role? newValue) {
                  setState(() {
                    _selectedRole = newValue;
                  });
                },
              ),
            SizedBox(height: 16),
            Row(
              mainAxisAlignment: MainAxisAlignment.end,
              children: [
                TextButton(
                  onPressed: () {
                    Navigator.of(context).pop(false);
                  },
                  child: Text(
                    'Cancelar',
                    style: TextStyle(color: GridColors.textSecondary),
                  ),
                ),
                SizedBox(width: 8),
                ElevatedButton(
                  onPressed: _associateRole,
                  style: ElevatedButton.styleFrom(
                    backgroundColor: GridColors.buttonBackground,
                  ),
                  child: Text(
                    'Associar',
                    style: TextStyle(color: GridColors.buttonText),
                  ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}
